-- Corrosive Armor Tracker - Core Logic\n-- Tracks when opponents use Corrosive Armor ultimate (ability ID: 17878)\n\nCorrosiveArmorTracker = {}\nCorrosiveArmorTracker.CORROSIVE_ARMOR_ID = 17878\nCorrosiveArmorTracker.ADDON_NAME = \"CorrosiveArmorTracker\"\nCorrosiveArmorTracker.activeCorrosiveUnits = {}\n\n-- Initialize the addon when loaded\nfunction CorrosiveArmorTracker.Initialize()\n    -- Register for addon loaded event\n    EVENT_MANAGER:RegisterForEvent(CorrosiveArmorTracker.ADDON_NAME, EVENT_ADD_ON_LOADED, function(event, addonName)\n        if addonName ~= CorrosiveArmorTracker.ADDON_NAME then return end\n        \n        -- Initialize saved variables with defaults\n        if CorrosiveArmorTrackerSavedVars == nil then\n            CorrosiveArmorTrackerSavedVars = {\n                enabledSound = true,\n                enabledVisual = true\n            }\n        end\n        \n        -- Initialize UI module\n        if CorrosiveArmorTracker.UI and CorrosiveArmorTracker.UI.Initialize then\n            CorrosiveArmorTracker.UI.Initialize()\n        end\n        \n        -- Initialize Settings module\n        if CorrosiveArmorTracker.Settings and CorrosiveArmorTracker.Settings.InitializeSettings then\n            CorrosiveArmorTracker.Settings.InitializeSettings()\n        end\n        \n        d(\"Corrosive Armor Tracker loaded. Use /cat for commands.\")\n    end)\n    \n    -- Register for effect changed event to track Corrosive Armor buff\n    EVENT_MANAGER:RegisterForEvent(CorrosiveArmorTracker.ADDON_NAME, EVENT_EFFECT_CHANGED, function(eventCode, changeType, effectSlot, effectName, unitTag, beginTime, endTime, stackCount, iconName, buffType, effectType, abilityType, statusEffectType, unitName, unitId, abilityId, sourceType)\n        CorrosiveArmorTracker.OnEffectChanged(eventCode, changeType, effectSlot, effectName, unitTag, beginTime, endTime, stackCount, iconName, buffType, effectType, abilityType, statusEffectType, unitName, unitId, abilityId, sourceType)\n    end)\n    \n    -- Register for reticle target changed to update warning display\n    EVENT_MANAGER:RegisterForEvent(CorrosiveArmorTracker.ADDON_NAME, EVENT_RETICLE_TARGET_CHANGED, function()\n        CorrosiveArmorTracker.OnReticleTargetChanged()\n    end)\nend\n\n-- Handle effect changes (buffs/debuffs gained or faded)\nfunction CorrosiveArmorTracker.OnEffectChanged(eventCode, changeType, effectSlot, effectName, unitTag, beginTime, endTime, stackCount, iconName, buffType, effectType, abilityType, statusEffectType, unitName, unitId, abilityId, sourceType)\n    -- Only track Corrosive Armor ability\n    if abilityId ~= CorrosiveArmorTracker.CORROSIVE_ARMOR_ID then return end\n    \n    -- Buff gained\n    if changeType == EFFECT_RESULT_GAINED then\n        CorrosiveArmorTracker.activeCorrosiveUnits[unitName] = {\n            unitTag = unitTag,\n            endTime = endTime,\n            unitName = unitName\n        }\n        -- Update display if hovering this unit\n        CorrosiveArmorTracker.OnReticleTargetChanged()\n    -- Buff faded\n    elseif changeType == EFFECT_RESULT_FADED then\n        CorrosiveArmorTracker.activeCorrosiveUnits[unitName] = nil\n        -- Update display\n        CorrosiveArmorTracker.OnReticleTargetChanged()\n    end\nend\n\n-- Handle reticle target changes to show/hide warning\nfunction CorrosiveArmorTracker.OnReticleTargetChanged()\n    local unitName = GetUnitName(\"reticleover\")\n    \n    -- Check if the hovered unit has active Corrosive Armor\n    if unitName and CorrosiveArmorTracker.IsUnitTracked(unitName) then\n        if CorrosiveArmorTracker.UI and CorrosiveArmorTracker.UI.ShowWarning then\n            CorrosiveArmorTracker.UI.ShowWarning(unitName)\n        end\n    else\n        if CorrosiveArmorTracker.UI and CorrosiveArmorTracker.UI.HideWarning then\n            CorrosiveArmorTracker.UI.HideWarning()\n        end\n    end\nend\n\n-- Check if a unit is being tracked with Corrosive Armor buff\nfunction CorrosiveArmorTracker.IsUnitTracked(unitName)\n    return CorrosiveArmorTracker.activeCorrosiveUnits[unitName] ~= nil\nend\n\n-- Initialize the addon when the file loads\nCorrosiveArmorTracker.Initialize()